SELECT u.user_name,u.user_code,ur.role_name,ur.user_name AS 'recomUserName', ur.user_code AS 'recomUserCode',r.uuid FROM tz_user_recom r LEFT JOIN tz_user u ON r.user_id=u.user_id LEFT JOIN tz_user ur ON r.recom_user_id=ur.user_id where 1=1
and ur.user_name=#{recomUserName}
and (u.user_name=#{userName} or u.user_code=#{userName})
and r.recom_user_id in
#{item}
ORDER BY r.create_time desc

SELECT u.user_id,u.user_name,u.user_code,u.role_name,ur.user_name AS 'recomUserName', ur.user_code AS 'recomUserCode' FROM tz_user u LEFT JOIN tz_user ur ON u.user_recom=ur.user_id where 1=1
and ur.user_name=#{recomUserName}
and (u.user_name=#{userName} or u.user_code=#{userName})
and u.user_recom in
#{item}
ORDER BY u.create_time desc
